      'KPIs por campanha:',
      ...(r.campaigns||[]).slice(0,12).map(c =>
        `  - ${c.campaign_name||c.campaign_id} (${c.objective||'?'}): gasto R$${(c.spend||0).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}, ROAS ${(c.roas||0).toFixed(2)}, leads ${c.leads||0}, compras ${c.purchases||0}, conversas ${c.conversations||0}`
      ),
      '',
      'Anomalias detectadas:',
      ...(r.anomalies||[]).slice(0,12).map(a =>
        `  - [${a.severity.toUpperCase()}] ${a.campaign_name||a.campaign_id}: ${a.diagnosis}`
      ),
    ];
    if (r.diagnosis) lines.push('', 'Diagnóstico IA anterior:', r.diagnosis);
    contextSummary = lines.join('\n');
  } catch(e) { contextSummary = 'Erro ao carregar contexto do relatório: ' + e.message; }
}

return [{json: {skip: false, to: senderNumber, message: message, contextSummary: contextSummary}}];
